186	async function mockWorkerProgress(page: import('@playwright/test').Page) {
187		const subscriptions = new Map<
188			string,
189			Array<{ id: string; ws: { send: (message: string) => void } }>
190		>();
191	
192		await page.routeWebSocket('**/graphql', (ws) => {
193			ws.onMessage((msg) => {
194				const parsed = JSON.parse(msg as string) as {
195					id?: string;
196					type: string;
197					payload?: { query?: string; variables?: { workerID?: string } };
198				};
199	
200				if (parsed.type === 'connection_init') {
201					ws.send(JSON.stringify({ type: 'connection_ack' }));
202					return;
203				}
204	
205				if (
206					parsed.type === 'subscribe' &&
207					parsed.id &&
208					parsed.payload?.query?.includes('workerProgress')
209				) {
210					const workerID = parsed.payload.variables?.workerID;
211					if (!workerID) return;
212					const existing = subscriptions.get(workerID) ?? [];
213					existing.push({ id: parsed.id, ws });
214					subscriptions.set(workerID, existing);
215				}
216			});
217		});
218	
219		return {
220			hasSubscription(workerID: string) {
221				return (subscriptions.get(workerID)?.length ?? 0) > 0;
222			},
223			send(workerID: string, phase: string) {
224				const entries = subscriptions.get(workerID) ?? [];
225				for (const entry of entries) {
226					entry.ws.send(
227						JSON.stringify({
228							id: entry.id,
229							type: 'next',
230							payload: {
231								data: {
232									workerProgress: {
233										eventID: `${workerID}-${phase}`,
234										workerID,
235										phase,
236										timestamp: '2026-04-22T12:00:00Z',
237										logLine: null,
238										beadID: null
239									}
240								}
241							}
242						})
243					);
244				}
245			}
246		};
247	}
